import React, { useState } from "react";
import "./App.css";

function App() {
  const [form, setForm] = useState({
    name: "",
    mobile: "",
    email: "",
    idType: "",
    idNumber: "",
    description: "",
  });

  const [errors, setErrors] = useState({});
  const [message, setMessage] = useState("");

  // Handle input change
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Validation logic
  const validate = () => {
    let newErrors = {};

    if (!form.name) newErrors.name = "Name is required";

    if (!form.mobile || !/^[0-9]{10}$/.test(form.mobile)) {
      newErrors.mobile = "Valid 10-digit mobile required";
    }

    if (!form.email || !/\S+@\S+\.\S+/.test(form.email)) {
      newErrors.email = "Valid email required";
    }

    if (!form.idType) newErrors.idType = "ID type required";
    if (!form.idNumber) newErrors.idNumber = "ID number required";
    if (!form.description) newErrors.description = "Description required";

    setErrors(newErrors);

    return Object.keys(newErrors).length === 0;
  };

  // Submit form
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validate()) return;

    try {
      const res = await fetch("http://localhost:8080/api/requests", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(form),
      });

      if (res.ok) {
        const data = await res.json();
        setMessage("Help Request Created! Ticket ID: " + data.ticketId);

        setForm({
          name: "",
          mobile: "",
          email: "",
          idType: "",
          idNumber: "",
          description: "",
        });
      } else {
        setMessage("Error creating request");
      }
    } catch (err) {
      setMessage("Server not reachable");
    }
  };

  return (
    <div className="container">
      <h1>LocalHelp Request</h1>

      <form onSubmit={handleSubmit}>
        <input
          name="name"
          placeholder="Full Name"
          value={form.name}
          onChange={handleChange}
        />
        <p className="error">{errors.name}</p>

        <input
          name="mobile"
          placeholder="Mobile Number"
          value={form.mobile}
          onChange={handleChange}
        />
        <p className="error">{errors.mobile}</p>

        <input
          name="email"
          placeholder="Email"
          value={form.email}
          onChange={handleChange}
        />
        <p className="error">{errors.email}</p>

        <input
          name="idType"
          placeholder="ID Type (Aadhar / PAN)"
          value={form.idType}
          onChange={handleChange}
        />
        <p className="error">{errors.idType}</p>

        <input
          name="idNumber"
          placeholder="ID Number"
          value={form.idNumber}
          onChange={handleChange}
        />
        <p className="error">{errors.idNumber}</p>

        <textarea
          name="description"
          placeholder="Describe your help request"
          value={form.description}
          onChange={handleChange}
        />
        <p className="error">{errors.description}</p>

        <button type="submit">Raise Help Request</button>
      </form>

      <h3>{message}</h3>
    </div>
  );
}

export default App;
